1	// MHPCO Claim Office - Policy quoting and claim processing system
2	
3	const ITEM_TYPE_PREMIUMS: Record<string, number> = {
4	  Sword: 50,
5	  Amulet: 100,
6	  Staff: 75,
7	  Potion: 60,
8	};
9	
10	const FIRST_INSURANCE_SURCHARGE = 1.1;
11	const LOYALTY_DISCOUNT = 0.8; // -20% discount for 2+ years
12	const CURSED_ITEM_SURCHARGE = 1.5;
13	const HIGH_ENCHANTMENT_SURCHARGE = 1.3; // +30% for enchantmentLevel >= 5
14	
15	export interface Item {
16	  type: string;
17	  insuranceModifier?: string;
18	  yearsInsured?: number;
19	  cursed?: boolean;
20	  enchantmentLevel?: number;
21	}
22	
23	const applyModifier = (value: number, multiplier: number, shouldApply: boolean): number => {
24	  return shouldApply ? value * multiplier : value;
25	};
26	
27	const applyModifiers = (premium: number, item: Item): number => {
28	  const modifiers = [
29	    { multiplier: FIRST_INSURANCE_SURCHARGE, condition: item.insuranceModifier === "first" },
30	    { multiplier: LOYALTY_DISCOUNT, condition: item.yearsInsured !== undefined && item.yearsInsured >= 2 },
31	    { multiplier: CURSED_ITEM_SURCHARGE, condition: item.cursed === true },
32	    { multiplier: HIGH_ENCHANTMENT_SURCHARGE, condition: item.enchantmentLevel !== undefined && item.enchantmentLevel >= 5 },
33	  ];
34	
35	  return modifiers.reduce((adjusted, mod) => applyModifier(adjusted, mod.multiplier, mod.condition), premium);
36	};
37	
38	const roundUpInMHPCOsFavor = (value: number): number => {
39	  const standardRound = Math.round(value);
40	  return value > standardRound ? standardRound + 1 : standardRound;
41	};
42	
43	export function quotePolicy(items: Item[]): number {
44	  const total = items.reduce((sum, item) => {
45	    if (!(item.type in ITEM_TYPE_PREMIUMS)) {
46	      throw new Error(`Unknown item type: ${item.type}`);
47	    }
48	    const basePremium = ITEM_TYPE_PREMIUMS[item.type];
49	    const adjustedPremium = applyModifiers(basePremium, item);
50	    return sum + Math.round(adjustedPremium * 100) / 100;
51	  }, 0);
52	  return roundUpInMHPCOsFavor(total);
53	}
54	
55	const INDIVIDUAL_COMPONENT_PRICE = 25;
56	const COMPONENT_BLOCK_SIZE = 3;
57	const COMPONENT_BLOCK_PRICE = 60;
58	
59	const CLAIM_DEDUCTIBLE = 100;
60	const INSURANCE_CAP_MULTIPLIER = 2;
61	const HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD = 8;
62	const HIGH_ENCHANTMENT_REIMBURSEMENT_RATE = 0.5;
63	
64	export function quoteComponent(items: Item[]): number {
65	  const basePrice = items.length === COMPONENT_BLOCK_SIZE ? COMPONENT_BLOCK_PRICE : INDIVIDUAL_COMPONENT_PRICE;
66	  const price = items.length === 1 ? applyModifiers(basePrice, items[0]) : basePrice;
67	  return price;
68	}
69	
70	const applyInsuranceCap = (amount: number, insuranceSum: number, dragonMaterial: boolean): number => {
71	  if (dragonMaterial) {
72	    return amount;
73	  }
74	  const cap = insuranceSum * INSURANCE_CAP_MULTIPLIER;
75	  return Math.min(amount, cap);
76	};
77	
78	const applyEnchantmentReduction = (reimbursement: number, enchantmentLevel?: number): number => {
79	  if (enchantmentLevel !== undefined && enchantmentLevel >= HIGH_ENCHANTMENT_REIMBURSEMENT_THRESHOLD) {
80	    return reimbursement * HIGH_ENCHANTMENT_REIMBURSEMENT_RATE;
81	  }
82	  return reimbursement;
83	};
84	
85	const validateItemInPolicy = (itemType?: string): void => {
86	  if (itemType !== undefined && !(itemType in ITEM_TYPE_PREMIUMS)) {
87	    throw new Error(`Item not in policy: ${itemType}`);
88	  }
89	};
90	
91	const validateQuantityMismatch = (damagedQuantity?: number, insuredQuantity?: number): void => {
92	  if (damagedQuantity !== undefined && insuredQuantity !== undefined && damagedQuantity > insuredQuantity) {
93	    throw new Error("Damaged quantity exceeds insured quantity");
94	  }
95	};
96	
97	const processMultipleDamageEvents = (damageEvents: number[]): number => {
98	  let total = 0;
99	  let deductibleApplied = false;
100	  for (const event of damageEvents) {
101	    if (!deductibleApplied) {
102	      total += Math.max(0, event - CLAIM_DEDUCTIBLE);
103	      deductibleApplied = true;
104	    } else {
105	      total += event;
106	    }
107	  }
108	  return total;
109	};
110	
111	export function processClaim(damage: number, insuranceSum?: number, enchantmentLevel?: number, dragonMaterial?: boolean, itemType?: string, damageEvents?: number[], damagedQuantity?: number, insuredQuantity?: number): number {
112	  if (damage < 0) {
113	    throw new Error("Damage amount cannot be negative");
114	  }
115	  validateItemInPolicy(itemType);
116	  validateQuantityMismatch(damagedQuantity, insuredQuantity);
117	  if (damage === 0) {
118	    return 0;
119	  }
120	
121	  // Handle multiple damage events
122	  if (damageEvents !== undefined && damageEvents.length > 0) {
123	    return processMultipleDamageEvents(damageEvents);
124	  }
125	
126	  const afterDeductible = damage - CLAIM_DEDUCTIBLE;
127	  if (insuranceSum !== undefined) {
128	    const cappedAmount = applyInsuranceCap(afterDeductible, insuranceSum, dragonMaterial ?? false);
129	    return applyEnchantmentReduction(cappedAmount, enchantmentLevel);
130	  }
131	  return afterDeductible;
132	}
