6	    expect(quotePolicy([])).toBe(0);
7	  });
8	  it("should return base premium for single Sword", () => {
9	    expect(quotePolicy([{ type: "Sword" }])).toBe(50);
10	  });
11	  it("should return sum of base premiums for multiple items", () => {
12	    expect(quotePolicy([{ type: "Sword" }, { type: "Sword" }])).toBe(100);
13	  });
14	  it("should return base premium for Amulet", () => {
15	    expect(quotePolicy([{ type: "Amulet" }])).toBe(100);
16	  });
17	  it("should return base premium for Staff", () => {
18	    expect(quotePolicy([{ type: "Staff" }])).toBe(75);
19	  });
20	  it("should return base premium for Potion", () => {
21	    expect(quotePolicy([{ type: "Potion" }])).toBe(60);
22	  });
23	  it("should return total with first insurance modifier (+10%)", () => {
24	    expect(quotePolicy([{ type: "Sword", insuranceModifier: "first" }])).toBe(55);
25	  });
26	  it("should return total with loyalty discount (-20%) for 2+ years", () => {
27	    expect(quotePolicy([{ type: "Sword", yearsInsured: 2 }])).toBe(40);
28	  });
29	  it("should return total with cursed item surcharge (50%)", () => {
30	    expect(quotePolicy([{ type: "Sword", cursed: true }])).toBe(75);
31	  });
32	  it("should return total with high enchantment surcharge (30%) for ≥5", () => {
33	    expect(quotePolicy([{ type: "Sword", enchantmentLevel: 5 }])).toBe(65);
34	  });
35	  it("should round premium up (away from zero) in MHPCO's favor", () => {
36	    // Test that rounding goes UP (ceiling) not down (floor): 82.1 should become 83 not 82
37	    // Sword 50: 50 * 1.1 (first) * 1.5 (cursed) = 82.5 -> must round to 83 to favor MHPCO
38	    expect(quotePolicy([{ type: "Sword", insuranceModifier: "first", cursed: true }])).toBe(83);
39	  });
40	  it.todo("should apply processing fee (+5 G) to final premium");
41	  it("should reject unknown item type", () => {
42	    expect(() => quotePolicy([{ type: "UnknownItem" }])).toThrow();
43	  });
44	});
45	
46	describe("MHPCO Claim Office - Claim Operation", () => {
47	  it("should return 0 for zero damage amount", () => {
48	    expect(processClaim(0)).toBe(0);
49	  });
50	  it("should subtract 100 G deductible from single damage claim", () => {
51	    expect(processClaim(100)).toBe(0);
52	  });
53	  it.todo("should reimburse full amount for damage under cap (2x insurance sum)");
54	  it("should apply 100 G deductible to multiple damage events", () => {
55	    expect(processClaim(100, 200, undefined, false, undefined, [100, 100])).toBe(100);
56	  });
57	  it("should cap payout at 2x the insurance sum", () => {
58	    expect(processClaim(400, 100)).toBe(200);
59	  });
60	  it("should apply 50% reimbursement for enchantment ≥8 damage", () => {
61	    expect(processClaim(400, 100, 8)).toBe(100);
62	  });
63	  it("should apply 100% reimbursement for dragon material damage", () => {
64	    expect(processClaim(400, 100, undefined, true)).toBe(300);
65	  });
66	  it("should reject claim for item not in policy", () => {
67	    expect(() => processClaim(100, 50, undefined, false, "UnknownItem")).toThrow();
68	  });
69	  it("should reject negative damage amount", () => {
70	    expect(() => processClaim(-50)).toThrow();
71	  });
72	  it("should reject claim with more damages of type than insured quantity", () => {
73	    // Insuring 1 Sword but claiming damage for 2 Sword items should be rejected
74	    expect(() => processClaim(200, 100, undefined, false, "Sword", undefined, 2, 1)).toThrow();
75	  });
76	});
77	
78	describe("MHPCO Claim Office - Component Bundle Pricing", () => {
79	  it("should charge 25 G per individual component", () => {
80	    expect(quoteComponent([{ type: "Sword" }])).toBe(25);
81	  });
82	  it("should charge 60 G for block of 3 identical components", () => {
83	    expect(quoteComponent([{ type: "Sword" }, { type: "Sword" }, { type: "Sword" }])).toBe(60);
84	  });
85	  it("should apply premium modifiers to component pricing", () => {
86	    expect(quoteComponent([{ type: "Sword", cursed: true }])).toBe(37.5);
87	  });
88	});
